import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Installing Java on macOS","description":"A step-by-step guide on how to install Java on macOS.","frontmatter":{"title":"Installing Java on macOS","description":"A step-by-step guide on how to install Java on macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"players/installing-java/macos.md","filePath":"players/installing-java/macos.md","lastUpdated":1768516421000}`);var c={name:`players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Java on macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Java on macOS”">​</a></h1><p>This guide will walk you through installing Java 21 on macOS.</p><p>The Minecraft Launcher comes with its own Java installation, so this section is only relevant if you want to use the Fabric <code>.jar</code> based installer, or if you want to use the Minecraft Server <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Check if Java Is Already Installed <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Check if Java Is Already Installed”">​</a></h2><p>In Terminal (located in <code>/Applications/Utilities/Terminal.app</code>) type the following, and press <kbd>Enter</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You should see something like the following:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Notice the version number: in the example above it is <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>To use Minecraft 1.21.11, you&#39;ll need at least Java 21 installed.</p><p>If this command displays any version lower than 21, you&#39;ll need to update your existing Java installation; keep reading this page.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Downloading and Installing Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Downloading and Installing Java 21”">​</a></h2><p>We recommend using <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium&#39;s build of OpenJDK 21</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Temurin Java Download Page" loading="lazy"></p><p>Make sure to select version &quot;21 - LTS&quot;, and choose the <code>.PKG</code> installer format. You should also choose the correct architecture depending on your system&#39;s chip:</p><ul><li>If you have an Apple M-series chip, choose <code>aarch64</code> (the default)</li><li>If you have an Intel chip, choose <code>x64</code></li><li>Follow these <a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">instructions to know which chip is in your Mac</a></li></ul><p>After downloading the <code>.pkg</code> installer, open it and follow the prompts:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Temurin Java Installer" loading="lazy"></p><p>You will have to enter your administrator password to complete the installation:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="macOS Password Prompt" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Using Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Using Homebrew”">​</a></h3><p>If you already have <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> installed, you can install Java 21 using <code>brew</code> instead:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Verify That Java 21 Is Installed <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Verify That Java 21 Is Installed”">​</a></h2><p>Once the installation is complete, you can verify that Java 21 is active by opening Terminal again and typing <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>.</p><p>If the command succeeds, you should see something like this:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>If you encounter any issues, feel free to ask for help in the <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};